133	            end
134	
135	            assign sum_zero = add_subnormal && add_result_significand == 0;
136	
137	            // If the operation is unordered (either operand is NaN), treat the result as false
138	            always_comb
139	            begin
140	                unique case (fx4_instruction.alu_op)
141	                    OP_CMPGT_F: compare_result = !fx4_add_result_sign[lane_idx] && !fx4_equal[lane_idx] && !fx4_result_nan[lane_idx];
142	                    OP_CMPGE_F: compare_result = (!fx4_add_result_sign[lane_idx] || fx4_equal[lane_idx]) && !fx4_result_nan[lane_idx];
143	                    OP_CMPLT_F: compare_result = fx4_add_result_sign[lane_idx] && !fx4_equal[lane_idx] && !fx4_result_nan[lane_idx];
144	                    OP_CMPLE_F: compare_result = (fx4_add_result_sign[lane_idx] || fx4_equal[lane_idx]) && !fx4_result_nan[lane_idx];
145	                    OP_CMPEQ_F: compare_result = fx4_equal[lane_idx] && !fx4_result_nan[lane_idx];
146	                    OP_CMPNE_F: compare_result = !fx4_equal[lane_idx] || fx4_result_nan[lane_idx];
147	                    default: compare_result = 0;
148	                endcase
149	            end
150	
151	            // If the operands for multiplication are both normalized (start with a leading 1), then the
152	            // the maximum normalization shift is one place.
153	            // XXX does not handle subnormal product
154	            assign mul_normalize_shift = !fx4_significand_product[lane_idx][47];
155	            assign {mul_normalized_significand, mul_guard, mul_round, mul_sticky_bits} = mul_normalize_shift
156	                ? {fx4_significand_product[lane_idx][45:0], 1'b0}
157	                : fx4_significand_product[lane_idx][46:0];
158	            assign mul_sticky = |mul_sticky_bits;
159	            assign mul_round_tie = mul_guard && !(mul_round || mul_sticky);
160	            assign mul_round_up = mul_guard && (mul_round || mul_sticky);
161	            assign mul_do_round = mul_round_up || (mul_round_tie && mul_normalized_significand[0]);
162	            assign mul_rounded_significand = mul_normalized_significand + FLOAT32_SIG_WIDTH'(mul_do_round);
163	            assign mul_hidden_bit = mul_normalize_shift ? fx4_significand_product[lane_idx][46] : 1'b1;
164	            assign mul_round_overflow = mul_do_round && mul_rounded_significand == 0;
165	            always_comb
166	            begin
167	                if (!mul_hidden_bit)
168	                    mul_exponent = 0;    // Is subnormal
169	                else if (mul_normalize_shift && !mul_round_overflow)
170	                    mul_exponent = fx4_mul_exponent[lane_idx];
171	                else
