#include <stdio.h>

void __attribute__ ((noinline)) printVal(float f)
{
	int foo;
	*((float*) &foo) = f;
	printf("0x%08x\n", foo);
}

float a = 123.0;
float b = 11.1;
float c = 1.0;

int main()
{
	printVal(1.0f / a);		// CHECK: 0x3c053408
	printVal(1235.0f / b);	// CHECK: 0x42de85c5
	printVal(c / 0.4f);	// CHECK: 0x40200000
}
